import stripe
import os
from flask import Flask, redirect, request, jsonify, render_template
from stripe_checkout_guard import StripeFlask, verify_webhook
from stripe.error import CardError, InvalidRequestError
from dotenv import load_dotenv

# Load environment variables
load_dotenv()

# Initialize Stripe
stripe.api_key = os.environ.get("STRIPE_SECRET_KEY")
app = Flask(__name__)
stripe_ext = StripeFlask(app, stripe.api_key)


@app.route("/")
def index():
    """Render the checkout page"""
    return render_template("index.html")


@app.route("/create-checkout-session", methods=["POST"])
@stripe_ext.protect
def create_checkout_session():
    """Create a Stripe checkout session"""
    try:
        session = stripe.checkout.Session.create(
            payment_method_types=["card"],
            line_items=[
                {
                    "price_data": {
                        "currency": "usd",
                        "product_data": {
                            "name": "Premium Plan",
                            "description": "Access to premium features"
                        },
                        "unit_amount": 2000,  # $20.00 in cents
                    },
                    "quantity": 1,
                }
            ],
            mode="payment",
            success_url="http://localhost:5000/success?session_id={CHECKOUT_SESSION_ID}",
            cancel_url="http://localhost:5000/cancel",
        )
        return redirect(session.url, code=303)
    except CardError as e:
        return jsonify({"error": e.user_message}), 402
    except InvalidRequestError as e:
        return jsonify({"error": str(e)}), 400


@app.route("/success")
def success():
    """Handle successful payment"""
    session_id = request.args.get("session_id")
    return render_template(
        "success.html",
        session_id=session_id
    )


@app.route("/cancel")
def cancel():
    """Handle cancelled payment"""
    return render_template("cancel.html")


@app.route("/webhook", methods=["POST"])
def stripe_webhook():
    """Handle Stripe webhook events"""
    payload = request.get_data()
    sig_header = request.headers.get("Stripe-Signature")

    try:
        # Get webhook secret from environment
        webhook_secret = os.environ.get("STRIPE_WEBHOOK_SECRET")
        event = verify_webhook(payload, sig_header, webhook_secret)

        # Handle checkout session completed
        if event["type"] == "checkout.session.completed":
            session = event["data"]["object"]
            fulfill_order(session)

        return "", 200
    except ValueError:
        return "Invalid payload", 400
    except Exception as e:
        return f"Webhook error: {str(e)}", 400


def fulfill_order(session):
    """Process the order after successful payment"""
    # Add your order fulfillment logic here
    customer_email = session.get("customer_details", {}).get("email")
    session_id = session.get("id")

    print(f"Order fulfilled for {customer_email} (Session: {session_id})")
    # TODO: Add database operations, send confirmation email, etc.


if __name__ == "__main__":
    app.run(port=5000, debug=True)

